// معالجة كل درس: تحويل content إلى مصفوفة sections
const courses = rawCourses.map(course => {
    const newLessons = course.lessons.map(lesson => {
        const sections = parseSectionsFromContent(lesson.content);
        return {
            title: lesson.title,
            sections: sections,
            _raw: lesson.content
        };
    });
    return {
        ...course,
        lessons: newLessons
    };
});

